import { createServer } from 'http';
import type { AppConfig } from '@mydash/shared';
import type { Logger } from '../logging/index.js';
import type { ModuleRegistry } from '../modules/index.js';
import { createLogger } from '../logging/index.js';
import { loadConfig } from '../configuration/index.js';
import { createModuleRegistry } from '../modules/index.js';
import { createLifecycle } from './lifecycle.js';

export interface Application {
  logger: Logger;
  config: AppConfig;
  moduleRegistry: ModuleRegistry;
  start(): Promise<void>;
  stop(): Promise<void>;
}

export function createApplication(): Application {
  const config = loadConfig();
  const logger = createLogger('system', config.system.logLevel);
  const moduleRegistry = createModuleRegistry(logger, config);
  const httpServer = createServer();

  const lifecycle = createLifecycle({
    logger,
    moduleRegistry,
    httpServer,
  });

  return {
    logger,
    config,
    moduleRegistry,
    start: async () => {
      moduleRegistry.register({
        name: 'http-server',
        dependsOn: [],
        initialize: async () => {},
        shutdown: async () => {
          await new Promise<void>((resolve) => httpServer.close(() => resolve()));
        },
        healthCheck: async () => true,
        status: 0 as unknown as import('../modules/index.js').ModuleStatus,
      });
      await lifecycle.startup();
    },
    stop: () => lifecycle.shutdown(),
  };
}

import type { Logger } from '../logging/index.js';
import type { ModuleRegistry } from '../modules/index.js';
import type { Server } from 'http';

export interface ApplicationLifecycle {
  startup(): Promise<void>;
  shutdown(): Promise<void>;
  isReady(): boolean;
}

export interface LifecycleDependencies {
  logger: Logger;
  moduleRegistry: ModuleRegistry;
  httpServer: Server;
  wsServer?: { stop: () => Promise<void> };
  dbConnection?: { disconnect: () => Promise<void> };
  redisConnection?: { disconnect: () => Promise<void> };
  eventBus?: { stop: () => Promise<void> };
  queueManager?: { drain: () => Promise<void>; stop: () => Promise<void> };
  schedulerManager?: { stop: () => Promise<void> };
}

export function createLifecycle(deps: LifecycleDependencies): ApplicationLifecycle {
  let ready = false;
  const { logger, moduleRegistry, httpServer, wsServer, dbConnection, redisConnection, eventBus, queueManager, schedulerManager } = deps;

  async function gracefulShutdown(signal: string): Promise<void> {
    logger.info(`Received ${signal}, starting graceful shutdown...`);
    ready = false;

    // 1. Stop accepting new requests
    logger.info('Stopping HTTP server...');
    await new Promise<void>((resolve) => {
      httpServer.close(() => {
        logger.info('HTTP server stopped');
        resolve();
      });
    });

    // 2. Drain queues
    if (queueManager) {
      logger.info('Draining queue...');
      try { await queueManager.drain(); logger.info('Queue drained'); } catch (e) { logger.error('Queue drain failed', e instanceof Error ? e : new Error(String(e))); }
      try { await queueManager.stop(); logger.info('Queue stopped'); } catch (e) { logger.error('Queue stop failed', e instanceof Error ? e : new Error(String(e))); }
    }

    // 3. Stop scheduler
    if (schedulerManager) {
      logger.info('Stopping scheduler...');
      try { await schedulerManager.stop(); logger.info('Scheduler stopped'); } catch (e) { logger.error('Scheduler stop failed', e instanceof Error ? e : new Error(String(e))); }
    }

    // 4. Stop event bus
    if (eventBus) {
      logger.info('Stopping event bus...');
      try { await eventBus.stop(); logger.info('Event bus stopped'); } catch (e) { logger.error('Event bus stop failed', e instanceof Error ? e : new Error(String(e))); }
    }

    // 5. Stop WebSocket
    if (wsServer) {
      logger.info('Stopping WebSocket server...');
      try { await wsServer.stop(); logger.info('WebSocket server stopped'); } catch (e) { logger.error('WebSocket stop failed', e instanceof Error ? e : new Error(String(e))); }
    }

    // 6. Shutdown modules
    logger.info('Shutting down modules...');
    try { await moduleRegistry.shutdownAll(); logger.info('Modules shutdown complete'); } catch (e) { logger.error('Module shutdown failed', e instanceof Error ? e : new Error(String(e))); }

    // 7. Close PostgreSQL
    if (dbConnection) {
      logger.info('Closing database connection...');
      try { await dbConnection.disconnect(); logger.info('Database connection closed'); } catch (e) { logger.error('Database disconnect failed', e instanceof Error ? e : new Error(String(e))); }
    }

    // 8. Close Redis
    if (redisConnection) {
      logger.info('Closing Redis connection...');
      try { await redisConnection.disconnect(); logger.info('Redis connection closed'); } catch (e) { logger.error('Redis disconnect failed', e instanceof Error ? e : new Error(String(e))); }
    }

    // 9. Flush logger and exit
    logger.info('Graceful shutdown complete');
    process.exit(0);
  }

  return {
    async startup(): Promise<void> {
      const shutdownHandler = (signal: string) => {
        gracefulShutdown(signal).catch((err) => {
          logger.error('Shutdown failed', err instanceof Error ? err : new Error(String(err)));
          process.exit(1);
        });
      };

      process.on('SIGINT', () => shutdownHandler('SIGINT'));
      process.on('SIGTERM', () => shutdownHandler('SIGTERM'));

      await moduleRegistry.resolveAll();
      ready = true;
      logger.success('Application started successfully');
    },

    async shutdown(): Promise<void> {
      await gracefulShutdown('MANUAL');
    },

    isReady(): boolean {
      return ready;
    },
  };
}

import type { AnalyticsRepository } from '../../domain/analytics/repository.js';
import type { AggregatedMetric, AnomalyResult, AnalyticsSummary } from '../../domain/analytics/entities.js';
import type { DrizzleClient } from '../../persistence/connection.js';
import type { Logger } from '../../logging/index.js';
import { metrics } from '../../persistence/schema/monitoring.js';
import { eq, and, desc, gte } from 'drizzle-orm';

export class AnalyticsRepositoryImpl implements AnalyticsRepository {
  constructor(
    private readonly db: DrizzleClient,
    private readonly logger: Logger,
  ) {}

  async saveSummary(summary: AnalyticsSummary, workspaceId?: string): Promise<void> {
    const wsId = workspaceId ?? '';
    for (const aggregation of summary.aggregatedMetrics) {
      await this.saveAggregation(summary.serverId, wsId, aggregation);
    }
    if (summary.anomalies.length > 0) {
      await this.saveAnomalies(summary.serverId, wsId, summary.anomalies);
    }
    this.logger.debug('analytics summary saved', { serverId: summary.serverId, windowMs: summary.windowMs });
  }

  async getSummary(serverId: string, windowMs: number): Promise<AnalyticsSummary | null> {
    const aggregations = await this.getAggregations(serverId, 'cpu', 50);
    if (aggregations.length === 0) return null;

    return {
      serverId,
      windowMs,
      generatedAt: new Date().toISOString(),
      aggregatedMetrics: aggregations,
      trends: [],
      anomalies: await this.getAnomalies(serverId, new Date(Date.now() - windowMs)),
      efficiencyIndices: [],
    };
  }

  async saveAggregation(serverId: string, workspaceId: string, aggregation: AggregatedMetric): Promise<void> {
    await this.db.insert(metrics).values({
      id: crypto.randomUUID(),
      workspaceId,
      serverId,
      metricType: aggregation.metricType,
      data: aggregation as unknown as Record<string, unknown>,
      correlationId: crypto.randomUUID(),
      version: 1,
    });
  }

  async getAggregations(serverId: string, metricType: string, limit: number): Promise<AggregatedMetric[]> {
    const results = await this.db
      .select({ data: metrics.data })
      .from(metrics)
      .where(and(eq(metrics.serverId, serverId), eq(metrics.metricType, metricType)))
      .orderBy(desc(metrics.recordedAt))
      .limit(limit);

    return results.map((r: { data: unknown }) => r.data as AggregatedMetric);
  }

  async saveAnomalies(serverId: string, workspaceId: string, anomalies: AnomalyResult[]): Promise<void> {
    if (anomalies.length === 0) return;
    const values = anomalies.map(anomaly => ({
      id: crypto.randomUUID(),
      workspaceId,
      serverId,
      metricType: `anomaly:${anomaly.metricType}`,
      data: anomaly as unknown as Record<string, unknown>,
      correlationId: crypto.randomUUID(),
      version: 1,
    }));
    await this.db.insert(metrics).values(values);
  }

  async getAnomalies(serverId: string, since: Date): Promise<AnomalyResult[]> {
    const results = await this.db
      .select({ metricType: metrics.metricType, data: metrics.data })
      .from(metrics)
      .where(and(eq(metrics.serverId, serverId), gte(metrics.recordedAt, since)))
      .limit(100);

    return results
      .filter(r => r.metricType.startsWith('anomaly:'))
      .map(r => r.data as AnomalyResult);
  }
}

