import type { DrizzleClient } from '../connection.js';
import type { Logger } from '../../logging/index.js';
import { eq } from 'drizzle-orm';

export class BaseDrizzleRepository {
  protected readonly db: DrizzleClient;
  protected readonly logger: Logger;
  protected readonly table: unknown;

  constructor(db: DrizzleClient, logger: Logger, table: unknown) {
    this.db = db;
    this.logger = logger;
    this.table = table;
  }

  async findById(id: string): Promise<unknown> {
    const t = this.table as { id: unknown };
    const results = await this.db.select().from(t as never).where(eq(t.id as never, id as never)).limit(1);
    return (results as unknown[])[0] ?? null;
  }

  async findAll(): Promise<unknown[]> {
    return this.db.select().from(this.table as never) as Promise<unknown[]>;
  }

  async create(entity: unknown): Promise<unknown> {
    const results = await this.db.insert(this.table as never).values(entity as never).returning();
    return (results as unknown[])[0];
  }

  async update(id: string, data: unknown): Promise<unknown> {
    const t = this.table as { id: unknown };
    const results = await this.db.update(t as never)
      .set({ ...(data as object), updatedAt: new Date() } as never)
      .where(eq(t.id as never, id as never))
      .returning();
    return (results as unknown[])[0];
  }

  async delete(id: string): Promise<void> {
    const t = this.table as { id: unknown };
    await this.db.delete(t as never).where(eq(t.id as never, id as never));
  }

  async softDelete(id: string): Promise<void> {
    const t = this.table as { id: unknown };
    await this.db.update(t as never)
      .set({ deletedAt: new Date() } as never)
      .where(eq(t.id as never, id as never));
  }

  async exists(id: string): Promise<boolean> {
    const result = await this.findById(id);
    return result !== null;
  }

  async count(): Promise<number> {
    const results = await this.db.select().from(this.table as never);
    return (results as unknown[]).length;
  }
}

import { createServer } from 'http';
import type { ServiceContainer } from '../infrastructure/utilities.js';
import { createExpressApp } from './http/app.js';
import { createReadinessRouter } from './http/router.js';
import { createWebSocketServer } from './ws/server.js';
import { createTransportConfig } from './config.js';
import type { Logger } from '../logging/index.js';
import type { Server } from 'http';

export function registerTransport(container: ServiceContainer, env: Record<string, string | undefined>, logger: Logger): Server {
  const config = createTransportConfig(env);

  const readinessCheck = async (): Promise<boolean> => {
    try {
      const dbChecker = container.resolve('dbHealthChecker') as { check: () => Promise<{ status: string }> };
      const redisChecker = container.resolve('redisHealthChecker') as { check: () => Promise<{ status: string }> };
      const dbResult = await dbChecker.check();
      const redisResult = await redisChecker.check();
      return dbResult.status !== 'unhealthy' && redisResult.status !== 'unhealthy';
    } catch {
      return false;
    }
  };

  const registry = container.resolve('serviceRegistry') as { resolve: (key: string) => unknown } | undefined;
  const jwtSecret = env['JWT_SECRET'] ?? 'dev-secret';
  const app = createExpressApp(logger, jwtSecret, registry as Parameters<typeof createExpressApp>[2]);
  app.use('/readiness', createReadinessRouter(readinessCheck));

  const server = createServer(app);
  const wsServer = createWebSocketServer(server, logger, { path: String(config.wsPath) });
  app.set('wsServer', wsServer);

  server.listen(config.port, config.host, () => {
    logger.info(`server listening on ${config.host}:${String(config.port)}`);
  });

  container.register('httpServer', () => server);
  container.register('expressApp', () => app);

  return server;
}

import { describe, it, expect, vi } from 'vitest';
import { correlationIdMiddleware, requestLoggerMiddleware, errorHandlerMiddleware, notFoundMiddleware, validationMiddleware, rateLimiterMiddleware } from './middleware.js';
import type { Logger } from '../../logging/index.js';

const mockLogger: Logger = {
  trace: vi.fn(), debug: vi.fn(), info: vi.fn(), success: vi.fn(),
  warn: vi.fn(), error: vi.fn(), critical: vi.fn(), emergency: vi.fn(),
  child: vi.fn(),
};

function mockReq(overrides: Record<string, unknown> = {}) {
  return {
    headers: {},
    method: 'GET',
    path: '/test',
    ip: '127.0.0.1',
    app: { get: vi.fn() },
    ...overrides,
  } as never;
}

function mockRes() {
  const self: Record<string, ReturnType<typeof vi.fn>> = {};
  self.status = vi.fn(() => self);
  self.json = vi.fn(() => self);
  self.send = vi.fn(() => self);
  self.on = vi.fn((_e: string, _c: () => void) => self);
  self.end = vi.fn();
  self.getHeaders = vi.fn(() => ({}));
  return self as never;
}

describe('correlationIdMiddleware', () => {
  it('adds correlation ID if missing', () => {
    const req = mockReq({ headers: {} });
    const next = vi.fn();
    correlationIdMiddleware()(req, mockRes(), next);
    expect((req as any).headers['x-correlation-id']).toBeDefined();
    expect(next).toHaveBeenCalled();
  });

  it('preserves existing correlation ID', () => {
    const req = mockReq({ headers: { 'x-correlation-id': 'existing' } });
    const next = vi.fn();
    correlationIdMiddleware()(req, mockRes(), next);
    expect((req as any).headers['x-correlation-id']).toBe('existing');
    expect(next).toHaveBeenCalled();
  });
});

describe('requestLoggerMiddleware', () => {
  it('sets up finish listener', () => {
    const res = mockRes();
    const next = vi.fn();
    requestLoggerMiddleware(mockLogger)(mockReq({ headers: { 'x-correlation-id': 't1' } }), res, next);
    expect(next).toHaveBeenCalled();
  });
});

describe('errorHandlerMiddleware', () => {
  it('returns 500', () => {
    const res = mockRes();
    errorHandlerMiddleware(mockLogger)(new Error('Broke'), mockReq(), res, vi.fn());
    expect(mockLogger.error).toHaveBeenCalled();
  });
});

describe('notFoundMiddleware', () => {
  it('calls sendError with 404', () => {
    const res = mockRes();
    notFoundMiddleware()(mockReq({ method: 'POST', path: '/unknown' }), res);
  });
});

describe('validationMiddleware', () => {
  it('allows JSON content type', () => {
    const next = vi.fn();
    validationMiddleware()(mockReq({ method: 'POST', headers: { 'content-type': 'application/json' } }), mockRes(), next);
    expect(next).toHaveBeenCalled();
  });

  it('rejects non-JSON for mutations', () => {
    const res = mockRes();
    const next = vi.fn();
    validationMiddleware()(mockReq({ method: 'POST', headers: { 'content-type': 'text/plain' } }), res, next);
    expect(next).not.toHaveBeenCalled();
  });

  it('allows GET without content-type', () => {
    const next = vi.fn();
    validationMiddleware()(mockReq({ method: 'GET' }), mockRes(), next);
    expect(next).toHaveBeenCalled();
  });
});

describe('rateLimiterMiddleware', () => {
  it('allows requests under limit', () => {
    const next = vi.fn();
    rateLimiterMiddleware(5, 60000)(mockReq(), mockRes(), next);
    expect(next).toHaveBeenCalled();
  });

  it('rate limits after exceeding max', () => {
    const middleware = rateLimiterMiddleware(2, 60000);
    const req = mockReq();
    const res = mockRes();
    middleware(req, res, vi.fn());
    middleware(req, res, vi.fn());
    middleware(req, res, vi.fn());
    expect((res as any).status).toHaveBeenCalledWith(429);
  });
});

import { describe, it, expect, vi, afterEach, beforeEach } from 'vitest';
import { createServer, type Server } from 'http';
import { WsServer, type WsConnection } from './server.js';
import WebSocket from 'ws';
import type { Logger } from '../../logging/index.js';

const mockLogger: Logger = {
  trace: vi.fn(), debug: vi.fn(), info: vi.fn(), success: vi.fn(),
  warn: vi.fn(), error: vi.fn(), critical: vi.fn(), emergency: vi.fn(),
  child: vi.fn(() => mockLogger),
};

interface MockWs {
  on: ReturnType<typeof vi.fn>;
  send: ReturnType<typeof vi.fn>;
  readyState: number;
  ping: ReturnType<typeof vi.fn>;
  close: ReturnType<typeof vi.fn>;
  OPEN: number;
  CLOSED: number;
  CLOSING: number;
  CONNECTING: number;
}

function createMockWs(readyState: number = WebSocket.OPEN): MockWs {
  return {
    on: vi.fn(),
    send: vi.fn(),
    readyState,
    ping: vi.fn(),
    close: vi.fn(),
    OPEN: WebSocket.OPEN,
    CLOSED: WebSocket.CLOSED,
    CLOSING: WebSocket.CLOSING,
    CONNECTING: WebSocket.CONNECTING,
  };
}

function createConnection(ws: MockWs, overrides?: Partial<WsConnection>): WsConnection {
  return {
    ws: ws as unknown as WebSocket,
    id: 'c1',
    userId: null,
    workspaceId: null,
    connectedAt: new Date(),
    lastActivity: new Date(),
    subscriptions: new Set(),
    ...overrides,
  } as WsConnection;
}

describe('WsServer Integration', () => {
  let httpServer: Server;
  let wsServer: WsServer;

  beforeEach(() => {
    vi.clearAllMocks();
    httpServer = createServer();
  });

  afterEach(async () => {
    if (wsServer) await wsServer.stop();
    httpServer.close();
  });

  it('should create and start server', () => {
    wsServer = new WsServer(httpServer, mockLogger, { path: '/ws' });
    expect(wsServer.getConnectionManager()).toBeDefined();
    expect(wsServer.getSubscriptionManager()).toBeDefined();
    const metrics = wsServer.getMetrics();
    expect(metrics.connections).toBe(0);
    expect(metrics.channels).toBe(0);
  });

  it('should stop cleanly', async () => {
    wsServer = new WsServer(httpServer, mockLogger);
    await wsServer.stop();
    expect(mockLogger.info).toHaveBeenCalledWith('ws server stopped');
  });

  it('should broadcast to subscribers', () => {
    wsServer = new WsServer(httpServer, mockLogger);
    const mockWs = createMockWs();
    const conn = createConnection(mockWs, { subscriptions: new Set(['metrics']) });
    wsServer.getConnectionManager().add(mockWs as unknown as WebSocket, conn);
    wsServer.getSubscriptionManager().subscribe('metrics', mockWs as unknown as WebSocket);

    wsServer.broadcast('metrics', 'test.event', { hello: 'world' });
    expect(mockWs.send).toHaveBeenCalled();
    const sent = JSON.parse(mockWs.send.mock.calls[0][0] as string);
    expect(sent.type).toBe('test.event');
    expect(sent.channel).toBe('metrics');
    expect(sent.payload).toEqual({ hello: 'world' });
  });

  it('should broadcast to all connections', () => {
    wsServer = new WsServer(httpServer, mockLogger);
    const mockWs = createMockWs();
    const conn = createConnection(mockWs);
    wsServer.getConnectionManager().add(mockWs as unknown as WebSocket, conn);

    wsServer.broadcastAll('global.event', { msg: 'hello' });
    expect(mockWs.send).toHaveBeenCalled();
  });

  it('should not broadcast to CLOSED connections', () => {
    wsServer = new WsServer(httpServer, mockLogger);
    const mockWs = createMockWs(WebSocket.CLOSED);
    const conn = createConnection(mockWs, { subscriptions: new Set(['metrics']) });
    wsServer.getConnectionManager().add(mockWs as unknown as WebSocket, conn);
    wsServer.getSubscriptionManager().subscribe('metrics', mockWs as unknown as WebSocket);

    wsServer.broadcast('metrics', 'test', {});
    expect(mockWs.send).not.toHaveBeenCalled();
  });

  it('should report metrics with connection', () => {
    wsServer = new WsServer(httpServer, mockLogger);
    const mockWs = createMockWs();
    const conn = createConnection(mockWs, { userId: 'u1', workspaceId: 'ws-1' });
    wsServer.getConnectionManager().add(mockWs as unknown as WebSocket, conn);

    const metrics = wsServer.getMetrics();
    expect(metrics.connections).toBe(1);
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { ConnectionManager, SubscriptionManager } from './server.js';
import type { Logger } from '../../logging/index.js';

const mockLogger: Logger = {
  trace: vi.fn(), debug: vi.fn(), info: vi.fn(), success: vi.fn(),
  warn: vi.fn(), error: vi.fn(), critical: vi.fn(), emergency: vi.fn(),
  child: vi.fn(),
};

const OPEN = 1;

function createMockWs() {
  return {
    on: vi.fn(),
    send: vi.fn(),
    ping: vi.fn(),
    close: vi.fn(),
    readyState: OPEN,
  } as never;
}

describe('ConnectionManager', () => {
  let cm: ConnectionManager;

  beforeEach(() => {
    vi.clearAllMocks();
    cm = new ConnectionManager(mockLogger);
  });

  it('should start with zero connections', () => {
    expect(cm.count()).toBe(0);
  });

  it('should add and count connections', () => {
    const ws = createMockWs();
    cm.add(ws, { ws, id: 'conn-1', userId: null, workspaceId: null, connectedAt: new Date(), lastActivity: new Date(), subscriptions: new Set() });
    expect(cm.count()).toBe(1);
  });

  it('should remove connections', () => {
    const ws = createMockWs();
    cm.add(ws, { ws, id: 'conn-1', userId: null, workspaceId: null, connectedAt: new Date(), lastActivity: new Date(), subscriptions: new Set() });
    cm.remove(ws);
    expect(cm.count()).toBe(0);
  });

  it('should get connection by ws reference', () => {
    const ws = createMockWs();
    cm.add(ws, { ws, id: 'conn-1', userId: 'u1', workspaceId: 'ws-1', connectedAt: new Date(), lastActivity: new Date(), subscriptions: new Set() });
    const conn = cm.get(ws);
    expect(conn).toBeDefined();
    expect(conn!.userId).toBe('u1');
  });

  it('should return all connections', () => {
    const ws1 = createMockWs();
    const ws2 = createMockWs();
    cm.add(ws1, { ws: ws1, id: 'c1', userId: null, workspaceId: null, connectedAt: new Date(), lastActivity: new Date(), subscriptions: new Set() });
    cm.add(ws2, { ws: ws2, id: 'c2', userId: null, workspaceId: null, connectedAt: new Date(), lastActivity: new Date(), subscriptions: new Set() });
    expect(cm.getAll()).toHaveLength(2);
  });

  it('should return undefined for unknown ws', () => {
    expect(cm.get(createMockWs())).toBeUndefined();
  });

  it('should handle remove for unknown ws gracefully', () => {
    expect(() => cm.remove(createMockWs())).not.toThrow();
  });
});

describe('SubscriptionManager', () => {
  let sm: SubscriptionManager;
  let ws1: ReturnType<typeof createMockWs>;
  let ws2: ReturnType<typeof createMockWs>;

  beforeEach(() => {
    sm = new SubscriptionManager();
    ws1 = createMockWs();
    ws2 = createMockWs();
  });

  it('should subscribe to a channel', () => {
    sm.subscribe('metrics', ws1);
    expect(sm.getSubscribers('metrics')).toHaveLength(1);
  });

  it('should track channel count', () => {
    sm.subscribe('metrics', ws1);
    expect(sm.channelCount()).toBe(1);
  });

  it('should allow multiple subscribers to same channel', () => {
    sm.subscribe('metrics', ws1);
    sm.subscribe('metrics', ws2);
    expect(sm.getSubscribers('metrics')).toHaveLength(2);
  });

  it('should unsubscribe from a channel', () => {
    sm.subscribe('metrics', ws1);
    sm.subscribe('metrics', ws2);
    sm.unsubscribe('metrics', ws1);
    expect(sm.getSubscribers('metrics')).toHaveLength(1);
  });

  it('should remove channel when last subscriber unsubscribes', () => {
    sm.subscribe('metrics', ws1);
    sm.unsubscribe('metrics', ws1);
    expect(sm.channelCount()).toBe(0);
  });

  it('should unsubscribe from all channels', () => {
    sm.subscribe('metrics', ws1);
    sm.subscribe('alerts', ws1);
    sm.unsubscribeAll(ws1);
    expect(sm.channelCount()).toBe(0);
  });

  it('should return empty array for unknown channel', () => {
    expect(sm.getSubscribers('unknown')).toEqual([]);
  });

  it('should handle unsubscribe from unknown channel gracefully', () => {
    expect(() => sm.unsubscribe('unknown', ws1)).not.toThrow();
  });
});
